import{c as e,Q as a,j as s,m as n}from"./chunks/framework.iD28w_5a.js";const h=JSON.parse('{"title":"Commit Conventions / 提交信息规范","description":"","frontmatter":{},"headers":[],"relativePath":"ci/02-commit-conventions.md","filePath":"ci/02-commit-conventions.md","lastUpdated":1778066889000}'),d={name:"ci/02-commit-conventions.md"};function i(r,t,o,l,p,c){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="commit-conventions-提交信息规范" tabindex="-1">Commit Conventions / 提交信息规范 <a class="header-anchor" href="#commit-conventions-提交信息规范" aria-label="Permalink to &quot;Commit Conventions / 提交信息规范&quot;">​</a></h1><p>Cinux 遵循 <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a> 规范。</p><h2 id="format-格式" tabindex="-1">Format / 格式 <a class="header-anchor" href="#format-格式" aria-label="Permalink to &quot;Format / 格式&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>type(scope): description</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><strong>type</strong>（必填）：提交类型</li><li><strong>scope</strong>（可选）：影响范围</li><li><strong>description</strong>（必填）：简短描述，不超过 72 字符</li></ul><h2 id="types-提交类型" tabindex="-1">Types / 提交类型 <a class="header-anchor" href="#types-提交类型" aria-label="Permalink to &quot;Types / 提交类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>type</th><th>含义</th><th>是否影响代码</th></tr></thead><tbody><tr><td><code>feat</code></td><td>新功能</td><td>是</td></tr><tr><td><code>fix</code></td><td>缺陷修复</td><td>是</td></tr><tr><td><code>doc</code></td><td>文档更新</td><td>否</td></tr><tr><td><code>style</code></td><td>代码格式（不影响逻辑）</td><td>否</td></tr><tr><td><code>refactor</code></td><td>重构（不新增功能也不修复）</td><td>是</td></tr><tr><td><code>perf</code></td><td>性能优化</td><td>是</td></tr><tr><td><code>test</code></td><td>测试补充或修正</td><td>是</td></tr><tr><td><code>chore</code></td><td>构建、工具、依赖维护</td><td>否</td></tr><tr><td><code>ci</code></td><td>CI 配置变更</td><td>否</td></tr></tbody></table><h2 id="scopes-范围" tabindex="-1">Scopes / 范围 <a class="header-anchor" href="#scopes-范围" aria-label="Permalink to &quot;Scopes / 范围&quot;">​</a></h2><table tabindex="0"><thead><tr><th>scope</th><th>说明</th></tr></thead><tbody><tr><td><code>kernel</code></td><td>内核核心逻辑</td></tr><tr><td><code>boot</code></td><td>引导加载</td></tr><tr><td><code>mm</code></td><td>内存管理</td></tr><tr><td><code>fs</code></td><td>文件系统</td></tr><tr><td><code>driver</code></td><td>设备驱动</td></tr><tr><td><code>sched</code></td><td>进程调度</td></tr><tr><td><code>user</code></td><td>用户态程序</td></tr><tr><td><code>test</code></td><td>测试框架</td></tr><tr><td><code>doc</code></td><td>文档</td></tr><tr><td><code>build</code></td><td>构建系统（CMake）</td></tr><tr><td><code>tools</code></td><td>辅助工具</td></tr></tbody></table><p>scope 为可选字段。当改动涉及多个模块时可以省略。</p><h2 id="breaking-changes-破坏性变更" tabindex="-1">Breaking Changes / 破坏性变更 <a class="header-anchor" href="#breaking-changes-破坏性变更" aria-label="Permalink to &quot;Breaking Changes / 破坏性变更&quot;">​</a></h2><p>在 type 后加 <code>!</code> 或在 footer 中写 <code>BREAKING CHANGE:</code>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(mm)!: replace bitmap allocator with buddy system</span></span>
<span class="line"><span></span></span>
<span class="line"><span>BREAKING CHANGE: pmm_alloc/pmm_free API signature changed</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="examples-示例" tabindex="-1">Examples / 示例 <a class="header-anchor" href="#examples-示例" aria-label="Permalink to &quot;Examples / 示例&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(fs): add ext2 write support</span></span>
<span class="line"><span>fix(mm): fix page fault in pmm_free when addr is unaligned</span></span>
<span class="line"><span>doc: update tutorial 028 for ext2 filesystem</span></span>
<span class="line"><span>style: auto-format with clang-format</span></span>
<span class="line"><span>refactor(kernel): extract common interrupt handler logic</span></span>
<span class="line"><span>perf(sched): optimize round-robin scheduling with bitmap queue</span></span>
<span class="line"><span>test(mm): add stress test for physical memory manager</span></span>
<span class="line"><span>chore: upgrade GCC toolchain requirement to 14</span></span>
<span class="line"><span>ci: add kernel integration test job</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="pr-title-pr-标题规范" tabindex="-1">PR Title / PR 标题规范 <a class="header-anchor" href="#pr-title-pr-标题规范" aria-label="Permalink to &quot;PR Title / PR 标题规范&quot;">​</a></h2><p>PR 标题应与 squash merge 后生成的 commit message 一致：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(fs): add ext2 write support</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>当一个 PR 包含多个 commit 时，PR 标题应概括整体改动，squash merge 后这些 commit 将合并为一个。</p><h2 id="guidelines-编写指南" tabindex="-1">Guidelines / 编写指南 <a class="header-anchor" href="#guidelines-编写指南" aria-label="Permalink to &quot;Guidelines / 编写指南&quot;">​</a></h2><ul><li>description 使用<strong>祈使句</strong>（&quot;add feature&quot; 而非 &quot;added feature&quot;）</li><li>不以句号结尾</li><li>首字母小写</li><li>用英文撰写，与代码风格保持一致</li><li>每个 commit 只做一件事——如果改动涉及多个不相关模块，拆分为多个 commit</li></ul>`,21)])])}const u=e(d,[["render",i]]);export{h as __pageData,u as default};
